-- ============================================================
-- Seed: Daily Bible Verses (100 verses for recovery)
-- ============================================================

INSERT INTO daily_verses (reference, text, theme) VALUES

    ('Psalm 46:1', 'እግዚአብሔር መጠጊያችንና ኃይላችን፥ በታላቅ መከራም ረዳታችን ነው።', 'strength'),
    ('Romans 8:28', 'እግዚአብሔርንም ለሚወዱት እንደ አሳቡም ለተጠሩት ነገር ሁሉ ለበጎ እንዲደረግ እናውቃለን።', 'hope'),
    ('Philippians 4:13', 'ኃይልን በሚሰጠኝ በክርስቶስ ሁሉን እችላለሁ።', 'strength'),
    ('Isaiah 41:10', 'እኔ ከአንተ ጋር ነኝና አትፍራ፤ እኔ አምላክህ ነኝና አትደንግጥ፤ አበረታሃለሁ፥ እረዳህማለሁ፥ በጽድቄም ቀኝ እደግፍሃለሁ።', 'comfort'),
    ('1 Corinthians 10:13', 'ለሰው ሁሉ ከሚሆነው በቀር ምንም ፈተና አልደረሰባችሁም፤ ነገር ግን ከምትችሉት በላይ ትፈተኑ ዘንድ የማይፈቅድ እግዚአብሔር የታመነ ነው፥ ትታገሡም ዘንድ እንድትችሉ ከፈተናው ጋር መውጫውን ደግሞ ያደርግላችኋል።', 'temptation'),
    ('James 4:7', 'እንግዲህ ለእግዚአብሔር ተገዙ፤ ዲያብሎስን ግን ተቃወሙት ከእናንተም ይሸሻል።', 'temptation'),
    ('Galatians 5:1', 'በነጻነት ልንኖር ክርስቶስ ነጻ አወጣን፤ እንግዲህ ጸንታችሁ ቁሙ፥ እንደ ገናም በባርነት ቀንበር አትያዙ።', 'freedom'),
    ('John 8:36', 'እንግዲህ ልጁ ነጻ ካወጣችሁ በእውነት ነጻ ትሆናላችሁ።', 'freedom'),
    ('Romans 6:14', 'ኃጢአት አይገዛችሁምና፤ ከጸጋ በታች እንጂ ከሕግ በታች አይደላችሁምና።', 'freedom'),
    ('2 Corinthians 5:17', 'ስለዚህ ማንም በክርስቶስ ቢሆን አዲስ ፍጥረት ነው፤ አሮጌው ነገር አልፏል፤ እነሆ፥ ሁሉም አዲስ ሆኗል።', 'renewal'),
    ('Lamentations 3:22-23', 'ያልጠፋነው ከእግዚአብሔር ምሕረት የተነሣ ነው፤ ርኅራኄው አያልቅምና። ማለዳ ማለዳ አዲስ ነው፤ ታማኝነትህ ታላቅ ነው።', 'renewal'),
    ('Psalm 51:10', 'አምላክ ሆይ፥ ንጹሕ ልብን ፍጠርልኝ፥ የቀናውንም መንፈስ በውስጤ አድስ።', 'renewal'),
    ('Romans 12:2', 'የእግዚአብሔር ፈቃድ እርሱም በጎና ደስ የሚያሰኝ ፍጹምም የሆነው ምን እንደ ሆነ ፈትናችሁ ታውቁ ዘንድ በልባችሁ መታደስ ተለወጡ እንጂ ይህን ዓለም አትምሰሉ።', 'transformation'),
    ('Ephesians 4:22-24', 'ፊተኛ ኑሮአችሁን እያሰባችሁ እንደሚያታልል ምኞት የሚጠፋውን አሮጌውን ሰው እንድታስወግዱ፥ በልባችሁም መንፈስ እንድትታደሱ፥ ለእውነትና ለቅድስና በሚሆን ጽድቅ እንደ እግዚአብሔር ምሳሌ የተፈጠረውን አዲሱን ሰው እንድትለብሱ ተምራችኋል።', 'transformation'),
    ('Psalm 34:18', 'እግዚአብሔር ልባቸው ለተሰበረ ቅርብ ነው፥ መንፈሳቸው የ cane ውንም ያድናቸዋል።', 'comfort'),
    ('Matthew 11:28', 'እናንተ ደካሞች ሸክማችሁ የከበደ ሁሉ፥ ወደ እኔ ኑ፥ እኔም አሳርፋችኋለሁ።', 'comfort'),
    ('Isaiah 43:2', 'በውኃ ውስጥ ስታልፍ ከአንተ ጋር እሆናለሁ፥ በወንዞችም ውስጥ ስታልፍ አያሰጥሙህም፤ በእሳትም ውስጥ ስትሄድ አትቃጠልም፥ ነበልባሉም አይፈጅህም።', 'comfort'),
    ('Psalm 23:4', 'በሞት ጥላ መካከል እንኳ ብሄድ አንተ ከእኔ ጋር ነህና ክፉን አልፈራም፤ በትርህና ምርኩዝህ እነርሱ ያጽናኑኛል።', 'comfort'),
    ('Romans 8:37', 'በዚህ ሁሉ ግን በወደደን በእርሱ ከአሸናፊዎች እንበልጣለን።', 'victory'),
    ('1 John 4:4', 'ልጆች ሆይ፥ እናንተ ከእግዚአብሔር ናችሁ አሸንፋችኋቸውማል፥ በዓለም ካለው ይልቅ በእናንተ ያለው ታላቅ ነውና።', 'victory'),
    ('Revelation 12:11', 'እነርሱም ከበጉ ደም የተነሣ ከምስክራቸውም ቃል የተነሣ ድል ነሡት፥ ነፍሳቸውንም እስከ ሞት ድረስ አልወደዱም።', 'victory'),
    ('Psalm 18:2', 'እግዚአብሔር ዓለቴ፥ አምባዬ፥ መድኃኒቴ፥ አምላኬ፥ የምታመንበት ረዳቴ፥ ጋሻዬ፥ የደኅንነቴ ቀንድ፥ መጠጊያዬ ነው።', 'strength'),
    ('Isaiah 40:31', 'እግዚአብሔርን በመታመን የሚጠባበቁ ግን ኃይላቸውን ያድሳሉ፤ እንደ ንስር በክንፍ ይወጣሉ፤ ይሮጣሉ፥ አይታክቱም፤ ይሄዳሉ፥ አይደክሙም።', 'strength'),
    ('Ephesians 6:11', 'የዲያብሎስን ሽንገላ ትቃወሙ ዘንድ እንዲቻላችሁ የእግዚአብሔርን ዕቃ ጦር ሁሉ ልበሱ።', 'temptation'),
    ('1 Peter 5:8', 'በመጠን ኑሩ ንቁም፥ ባላጋራችሁ ዲያብሎስ የሚውጠውን ፈልጎ እንደሚያገሣ አንበሳ ይዞራልና፤', 'temptation'),
    ('Hebrews 4:15', 'ከኃጢአት በቀር በነገር ሁሉ እንደ እኛ የተፈተነ ነው እንጂ፥ በድካማችን ሊራራልን የማይችል ሊቀ ካህናት የለንም።', 'temptation'),
    ('Hebrews 12:1', 'እንግዲህ እነዚህን የሚያህሉ ምስክሮች እንደ ደመና በዙሪያችን ካሉልን፥ እኛ ደግሞ ሸክምን ሁሉ ቶሎም የሚከበንን ኃጢአት አስወግደን፥ የእምነታችንን ራስና ፈጻሚውን ኢየሱስን ተመልክተን፥ በፊታችን ያለውን ሩጫ በትዕግሥት እንሩጥ፤', 'perseverance'),
    ('James 1:12', 'በፈተና የሚጸና ሰው ምስጉን ነው፤ ከተፈተነ በኋላ ለሚወዱት ጌታ የሰጠውን የሕይወትን አክሊል ይቀበላልና።', 'perseverance'),
    ('Philippians 3:14', 'በክርስቶስ ኢየሱስ ከፍ ከፍ ላለው ለእግዚአብሔር መጥራት የሚሰጠውን የዋጋውን አክሊል ለማግኘት ወደ ግቡ እሮጣለሁ።', 'perseverance'),
    ('Psalm 40:1-2', 'እግዚአብሔርን ደጅ ጠናሁት፥ እርሱም ዘንበል አለልኝ ጩኸቴንም ሰማኝ። ከጥፋት ጕድጓድ ከረግረጉም ጭቃ አወጣኝ፥ እግሮቼንም በዓለት ላይ አቆማቸው፥ አካሄዴንም አቀና።', 'hope'),
    ('Jeremiah 29:11', 'ለእናንተ የማስባትን አሳብ እኔ አውቃለሁ፥ ፍጻሜና ተስፋ እሰጣችሁ ዘንድ የሰላም አሳብ ነው እንጂ የክፉ ነገር አይደለም፥ ይላል እግዚአብሔር።', 'hope'),
    ('Romans 15:13', 'የተስፋ አምላክም በመንፈስ ቅዱስ ኃይል በተስፋ እንድትበዙ በማመናችሁ ደስታንና ሰላምን ሁሉ ይሙላባችሁ።', 'hope'),
    ('Psalm 119:9', 'ጐበዝ መንገዱን በምን ያጠራል? ቃልህን በመጠበቅ ነው።', 'purity'),
    ('Matthew 5:8', 'ልበ ንጹሐን ብፁዓን ናቸው፥ እግዚአብሔርን ያዩታልና።', 'purity'),
    ('1 Thessalonians 4:3', 'ይህ የእግዚአብሔር ፈቃድ እርሱም መቀደሳችሁ ነውና፤ ከዝሙት እንድትርቁ፥', 'purity'),
    ('Job 31:1', 'ከዓይኖቼ ጋር ቃል ኪዳን አደረግሁ፤ እንግዲህ እንዴት ወደ ድንግል እመለከታለሁ?', 'purity'),
    ('Psalm 101:3', 'በዓይኖቼ ፊት ክፉ ነገርን አላኖርኩም፤ ሕግ ተላላፊዎችን ጠላሁ።', 'purity'),
    ('Proverbs 4:23', 'አካሄድ ሁሉ ከእርሱ ነውና ከሁሉ ይልቅ ልብህን ጠብቅ።', 'wisdom'),
    ('Proverbs 3:5-6', 'በፍጹም ልብህ በእግዚአብሔር ታመን፥ በራስህም ማስተዋል አትደገፍ፤ በመንገድህ ሁሉ እርሱን እወቅ፥ እርሱም ጎዳናህን ያቀናልሃል።', 'wisdom'),
    ('James 1:5', 'ከእናንተ ግን ማንም ጥበብ ቢጎድለው፥ ሳይነቅፍ ለሁሉ በልግስና የሚሰጠውን እግዚአብሔርን ይለምን፥ ለእርሱም ይሰጠዋል።', 'wisdom'),
    ('1 Corinthians 6:19-20', 'ወይስ ሥጋችሁ ከእግዚአብሔር የተቀበላችሁት በእናንተ የሚኖረው የመንፈስ ቅዱስ ቤተ መቅደስ እንደ ሆነ አታውቁም? በዋጋ ተገዝታችኋልና ለራሳችሁ አይደላችሁም፤ ስለዚህ በሥጋችሁ እግዚአብሔርን አክብሩ።', 'purity'),
    ('Romans 13:14', 'ነገር ግን ጌታን ኢየሱስ ክርስቶስን ልበሱት፥ ምኞቱንም እንዲፈጽም ለሥጋ አታስቡ።', 'temptation'),
    ('Colossians 3:2', 'በላይ ያለውን አስቡ እንጂ በምድር ያለውን አይደለም።', 'renewal'),
    ('2 Timothy 2:22', 'ከጎልማሳነት ክፉ ምኞት ግን ሽሽ፥ በንጹሕም ልብ ጌታን ከሚጠሩ ጋር ጽድቅን እምነትን ፍቅርን ሰላምን አጥብቀህ ተከተል።', 'purity'),
    ('Psalm 86:5', 'አንተ፥ ጌታ ሆይ፥ ቸርና ይቅር ባይ ነህና፥ ለሚጠሩህም ሁሉ ምሕረትህ ብዙ ነውና።', 'forgiveness'),
    ('1 John 1:9', 'በኃጢአታችን ብንናዘዝ ኃጢአታችንን ይቅር ሊለን ከአመጻም ሁሉ ሊያነጻን የታመነና ጻድቅ ነው።', 'forgiveness'),
    ('Micah 7:19', 'ተመልሶ ይምረናል፤ በደላችንን በትረ እግሩ ይረግጠዋል፥ ኃጢአታችንንም በባሕሩ ጥልቅ ይጥለዋል።', 'forgiveness'),
    ('Psalm 103:12', 'ምሥራቅ ከምዕራብ እንደሚርቅ፥ እንዲሁ ኃጢአታችንን ከእኛ አራቀ።', 'forgiveness'),
    ('Isaiah 1:18', 'ኑና እንዋቀስ ይላል እግዚአብሔር፤ ኃጢአታችሁ እንደ ቀይ ግምጃ ብትሆን እንደ በረዶ ትነጻለች፤ እንደ ደምም ብትቀላ እንደ ጠጉር ነጭ ትሆናለች።', 'forgiveness'),
    ('Romans 8:1', 'እንግዲህ በክርስቶስ ኢየሱስ ላሉት አሁን ኵነኔ የለባቸውም።', 'forgiveness'),
    ('Ephesians 1:7', 'በውድ ልጁም፥ እንደ ጸጋው ባለጠግነት መጠን፥ በደሙ የተደረገ ቤዛነታችንን አገኘን እርሱም የኃጢአት ይቅርታ።', 'forgiveness'),
    ('Hebrews 10:22', 'ከክፉ ሕሊና ለመንጻት ልባችንን ተረጭተን ሥጋችንንም በጥሩ ውኃ ታጥበን፥ በተረዳንበት እምነት በቅን ልብ እንቅረብ፤', 'forgiveness'),
    ('Galatians 6:1', 'ወንድሞች ሆይ፥ ሰው በማናቸውም በደል ቢገኝ፥ መንፈሳውያን የሆናችሁ እናንተ በየውሃት መንፈስ እንደዚህ ያለውን ሰው አቅኑት፤ አንተ ደግሞ እንዳትፈተን ራስህን ጠብቅ።', 'community'),
    ('Proverbs 27:17', 'ብረት ብረትን ይስለዋል፥ ሰውም ባልንጀራውን ይስላል።', 'community'),
    ('Hebrews 10:24-25', 'ለፍቅርና ለመልካምም ሥራ እንድንቀሰቀስ እርስ በርሳችን እንተያይ፤ አንዳንዶችም እንደሚያደርጉት፥ መሰብሰባችንን አንተው እርስ በርሳችን እንመካከር እንጂ፤', 'community'),
    ('Ecclesiastes 4:9-10', 'ለድካማቸው መልካም ዋጋ አላቸውና ከአንድ ይልቅ ሁለት መሆን ይሻላል። ቢወድቁ አንዱ ባልንጀራውን ያነሣዋልና፤ አንዱ ብቻውን ሆኖ በወደቀ ጊዜ የሚያነሣው ሌላ የሌለው ወዮለት።', 'community'),
    ('James 5:16', 'እንድትፈወሱ እርስ በርሳችሁ በኃጢአታችሁ ተናዘዙ፥ እርስ በርሳችሁም ጸልዩ፤ የጻድቅ ሰው ጸሎት በሥራዋ ታላቅ ኃይል ታደርጋለች።', 'community'),
    ('Matthew 18:20', 'ሁለት ወይም ሦስት በስሜ በሚሰበሰቡበት በዚያ በመካከላቸው እሆናለሁና።', 'community'),
    ('Psalm 55:22', 'ትከሻህን ለእግዚአብሔር ስጥ፥ እርሱም ይደግፍሃል፤ ለጻድቁም ለዘላለም መናወጥን አይሰጠውም።', 'trust'),
    ('Nahum 1:7', 'እግዚአብሔር ቸር ነው፥ በመከራ ቀንም መሸሸጊያ ነው፥ በእርሱ የሚታመኑትንም ያውቃቸዋል።', 'trust'),
    ('Psalm 37:5', 'መንገድህን ለእግዚአብሔር አደራ ስጥ፥ በእርሱም ታመን፥ እርሱም ያደርግልሃል።', 'trust'),
    ('Isaiah 26:3', 'በአንተ ታምናለችና በአንተ ላይ ለተደገፈች ነፍስ ፈጽመህ በሰላም ትጠብቃታለህ።', 'peace'),
    ('John 14:27', 'ሰላምን እተውላችኋለሁ፥ ሰላሜን እሰጣችኋለሁ፤ እኔ የምሰጣችሁ ዓለም እንደሚሰጥ አይደለም። ልባችሁ አይታወክ አትፍሩም።', 'peace'),
    ('Philippians 4:6-7', 'በነገር ሁሉ በጸሎትና በምልጃ ከምስጋና ጋር ልመናችሁን በእግዚአብሔር ፊት አስታውቁ እንጂ በአንዳች አትጨነቁ። ማስተዋልንም ሁሉ የሚያልፍ የእግዚአብሔር ሰላም ልባችሁንና አሳባችሁን በክርስቶስ ኢየሱስ ይጠብቃል።', 'peace'),
    ('Romans 5:1', 'እንግዲህ በእምነት ከጸደቅን በጌታችን በኢየሱስ ክርስቶስ በኩል በእግዚአብሔር ዘንድ ሰላምን እንያዝ፤', 'peace'),
    ('Psalm 32:1', 'መተላለፉ የተሰረየለት ኃጢአቱም የተከደነለት ምስጉን ነው።', 'blessing'),
    ('Numbers 6:24-26', 'እግዚአብሔር ይባርክህ ይጠብቅህም፤ እግዚአብሔር ፊቱን ያብራልህ፥ ይማርህም፤ እግዚአብሔር ፊቱን ወደ አንተ ያንሣ፥ ሰላምም ይስጥህ።', 'blessing'),
    ('Deuteronomy 31:8', 'እግዚአብሔርም ራሱ በፊታችሁ ይሄዳል፥ ከአንተም ጋር ይሆናል፥ አይጥልህም አይተውህምም፤ አትፍራ አትደንግጥም።', 'courage'),
    ('Joshua 1:9', 'በምትሄድበት ሁሉ አምላክህ እግዚአብሔር ከአንተ ጋር ነውና ጽና፥ አይዞህ፤ አትፍራ፥ አትደንግጥ ብዬ አላዘዝሁህምን?', 'courage'),
    ('2 Timothy 1:7', 'እግዚአብሔር የኃይልና የፍቅር ራስንም የመግዛት መንፈስ እንጂ የፍርሃት መንፈስ አልሰጠንምና።', 'courage'),
    ('Psalm 27:1', 'እግዚአብሔር ብርሃኔና መድኃኒቴ ነው፤ የሚያስፈራኝ ማን ነው? እግዚአብሔር የሕይወቴ መታመኛዋ ነው፤ የሚያስደነግጠኝ ማን ነው?', 'courage'),
    ('Hebrews 13:5', 'አካሄዳችሁ ያለ ገንዘብ ፍቅር ይሁን፥ ያላችሁም ይብቃችሁ፤ እርሱ ራሱ፦ አልለቅህም ከቶም አልተውህም ብሏልና፤', 'trust'),
    ('Psalm 145:18', 'እግዚአብሔር ለሚጠሩት ሁሉ፥ በእውነት ለሚጠሩት ሁሉ ቅርብ ነው።', 'trust'),
    ('Romans 8:38-39', 'ሞት ቢሆን፥ ሕይወትም ቢሆን፥ መላእክትም ቢሆኑ፥ ግዛቶችም ቢሆኑ፥ ያለውም ቢሆን፥ የሚመጣውም ቢሆን፥ ኃይላትም ቢሆኑ፥ ከፍታም ቢሆን፥ ዝቅታም ቢሆን፥ ሌላ ፍጥረትም ቢሆን በክርስቶስ ኢየሱስ በጌታችን ካለው ከእግዚአብሔር ፍቅር ሊለየን እንዳይችል ተረድቼአለሁ።', 'love'),
    ('John 3:16', 'በእርሱ የሚያምን ሁሉ የዘላለም ሕይወት እንዲኖረው እንጂ እንዳይጠፋ እግዚአብሔር አንድያ ልጁን እስኪሰጥ ድረስ ዓለሙን እንዲሁ ወዶአልና።', 'love'),
    ('1 John 4:18', 'ፍጹም ፍቅር ፍርሃትን አውጥቶ ይጥላል እንጂ በፍቅር ፍርሃት የለም፤ ፍርሃት ቅጣት አለውና፤ የሚፈራም ሰው ፍቅሩ ፍጹም አይደለም።', 'love'),
    ('Zephaniah 3:17', 'አምላክህ እግዚአብሔር በመካከልሽ ነው፥ እርሱ የሚያድን ኃያል ነው፤ በአንቺ ደስ ይለዋል፥ በፍቅሩም ያሳርፍሻል፥ በእልልታም በአንቺ ሐሴት ያደርጋል።', 'love'),
    ('1 Peter 1:13', 'ስለዚህ የልቦናችሁን ወገብ ታጥቃችሁና በመጠን ኖራችሁ፥ ኢየሱስ ክርስቶስ ሲገለጥ የምታገኙትን ጸጋ ፈጽማችሁ ተስፋ አድርጉ።', 'hope'),
    ('Colossians 1:13', 'እርሱ ከጨለማ ሥልጣን አዳነን፥ ወደ ፍቅሩም ልጅ መንግሥት አፈለሰን፤', 'freedom'),
    ('Psalm 107:13-14', 'በመከራቸው ወደ እግዚአብሔር ጮኹ፥ ከጭንቀታቸውም አዳናቸው። ከጨለማና ከሞት ጥላ አወጣቸው፥ እስራታቸውንም ሰበረ።', 'freedom'),
    ('Luke 4:18', 'የጌታ መንፈስ በእኔ ላይ ነው፥ ለድሆች ወንጌልን እሰብክ ዘንድ ቀብቶኛልና፤ ለታሰሩትም መፈታትን ለዕውሮችም ማየትን እሰብክ ዘንድ፥ የተቀጠቀጡትንም ነጻ አውጣ ዘንድ የተወደደችውንም የእግዚአብሔርን ዓመት እሰብክ ዘንድ ልኮኛል።', 'freedom'),
    ('Acts 3:19', 'እንግዲህ ከጌታ ፊት የማረፊያ ዘመን እንድትመጣላችሁ፥ ኃጢአታችሁም ይደመሰስ ዘንድ ንስሐ ግቡ ተመለሱም።', 'renewal'),
    ('Isaiah 61:3', 'በጽዮን ላሉት አልቃሾች አደርግላቸው ዘንድ፥ በአመድ ፋንታ ጌጥን፥ በልቅሶም ፋንታ የደስታን ዘይት፥ በኀዘንም መንፈስ ፋንታ የምስጋናን መጐናጸፊያ እሰጣቸው ዘንድ ልኮኛል፤', 'renewal'),
    ('Ezekiel 36:26', 'አዲስም ልብ እሰጣችኋለሁ አዲስም መንፈስ በውስጣችሁ አኖራለሁ፤ የድንጋዩንም ልብ ከሥጋችሁ አወጣለሁ የሥጋውንም ልብ እሰጣችኋለሁ።', 'transformation'),
    ('2 Corinthians 4:16', 'ስለዚህ አንታክትም፤ የውጭው ሰውነታችን ቢጠፋ እንኳ የውስጡ ሰውነታችን ዕለት ዕለት ይታደሳል።', 'perseverance'),
    ('Romans 5:3-4', 'ይህም ብቻ አይደለም፥ ነገር ግን መከራ ትዕግሥትን እንዲያደርግ፥ ትዕግሥትም ፈተናን ፈተናም ተስፋን እንዲያደርግ እያወቅን፥ በመከራችን ደግሞ እንመካለን፤', 'perseverance'),
    ('Psalm 46:10', 'ዕረፉ፥ እኔም አምላክ እንደ ሆንሁ እወቁ፤ በአሕዛብ ዘንድ ከፍ ከፍ እላለሁ፥ በምድርም ላይ ከፍ ከፍ እላለሁ።', 'peace'),
    ('Proverbs 28:13', 'ኃጢአቱን የሚሰውር አይቀናውም፤ የሚናዘዝባትና የሚተዋት ግን ምሕረትን ያገኛል።', 'forgiveness'),
    ('Matthew 5:3', 'በመንፈስ ድሆች የሆኑ ብፁዓን ናቸው፥ መንግሥተ ሰማያት የእነርሱ ናትና።', 'blessing'),
    ('Psalm 34:8', 'እግዚአብሔር ቸር እንደ ሆነ ቅመሱ እዩም፤ በእርሱ የሚታመን ሰው ምስጉን ነው።', 'blessing'),
    ('Ephesians 3:20', 'እንግዲህ በእኛ ውስጥ እንደሚሠራው ኃይል መጠን ከምንለምነው ወይም ከምናስበው ሁሉ ይልቅ እጅግ አብልጦ ሊያደርግ ለሚቻለው፥', 'hope'),
    ('Philippians 1:6', 'በእናንተ መልካምን ሥራ የጀመረው እስከ ኢየሱስ ክርስቶስ ቀን ድረስ እንዲፈጽመው ይህን ተረድቼአለሁና፤', 'hope'),
    ('Psalm 71:20', 'ብዙና ክፉ መከራን አሳየኸኝ፥ ተመልሰህም ሕያው አደረግኸኝ፥ ከምድር ጥልቅም ተመልሰህ አወጣኸኝ።', 'hope'),
    ('Joel 2:25', 'አንበጣና ደጎብያ ኵብኵባና ተምች፥ የበላችሁትን ዓመታት እመልስላችኋለሁ።', 'restoration'),
    ('Isaiah 43:19', 'እነሆ፥ አዲስ ነገርን አደርጋለሁ፤ እርሱም አሁን በቀል ይበቅላል፥ እናንተስ አታውቁትምምን? በምድረ በዳም መንገድን በበረሃም ወንዞችን አደርጋለሁ።', 'renewal'),
    ('Psalm 30:5', 'ቍጣው ለጥቂት ጊዜ ነውና፥ ሞገሱ ግን ለሕይወት ዘመን፤ ማልቀስ ማታ ይመጣል፥ ጠዋት ግን ደስታ ይሆናል።', 'hope')
;